// Blink detection using eye aspect ratio
function getEyeAspectRatio(landmarks, side) {
  if (side === 'left') {
    const upper = landmarks[159]; // upper eyelid center
    const lower = landmarks[145]; // lower eyelid center
    const outer = landmarks[33];  // outer corner
    const inner = landmarks[133]; // inner corner

    const vertical = Math.abs(upper.y - lower.y);
    const horizontal = Math.abs(outer.x - inner.x);
    return vertical / horizontal;
  }
  // Right eye: 386 (upper), 374 (lower), 263 (outer), 362 (inner)
  const upper = landmarks[386];
  const lower = landmarks[374];
  const outer = landmarks[263];
  const inner = landmarks[362];

  const vertical = Math.abs(upper.y - lower.y);
  const horizontal = Math.abs(outer.x - inner.x);
  return vertical / horizontal;
}

// EAR below ~0.2 typically means the eye is closed
const leftEAR = getEyeAspectRatio(landmarks, 'left');
const isBlinking = leftEAR < 0.2;

// Eyebrow raise detection
function isEyebrowRaised(landmarks, side) {
  const eyebrowPeak = side === 'left' ? landmarks[52] : landmarks[282];
  const eyeTop = side === 'left' ? landmarks[159] : landmarks[386];

  const distance = Math.abs(eyebrowPeak.y - eyeTop.y);
  return distance > 0.04; // threshold varies per face
}

