// Mouth open detection
function isMouthOpen(landmarks, threshold = 0.02) {
  const upperLip = landmarks[13];
  const lowerLip = landmarks[14];
  const mouthHeight = Math.abs(upperLip.y - lowerLip.y);
  return mouthHeight > threshold;
}

// Smile detection using mouth corner positions
function isSmiling(landmarks) {
  const leftCorner = landmarks[61];
  const rightCorner = landmarks[291];
  const mouthCenter = landmarks[13];

  // Corners rise above center when smiling
  const leftRise = mouthCenter.y - leftCorner.y;
  const rightRise = mouthCenter.y - rightCorner.y;

  return (leftRise + rightRise) / 2 > 0.01;
}

import { FaceLandmarker, FilesetResolver } from '@mediapipe/tasks-vision';

async function setupFaceLandmarker() {
  const vision = await FilesetResolver.forVisionTasks(
    'https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision/wasm'
  );

  const faceLandmarker = await FaceLandmarker.createFromOptions(vision, {
    baseOptions: {
      modelAssetPath:
        'https://storage.googleapis.com/mediapipe-models/face_landmarker/face_landmarker/float16/1/face_landmarker.task',
      delegate: 'GPU',
    },
    runningMode: 'VIDEO',
    numFaces: 1,
    outputFaceBlendshapes: true,
  });

  return faceLandmarker;
}

function detectLandmarks(faceLandmarker, video) {
  const result = faceLandmarker.detectForVideo(video, performance.now());

  if (result.faceLandmarks.length > 0) {
    const landmarks = result.faceLandmarks[0];

    // Each landmark has x, y, z (normalized 0-1)
    const noseTip = landmarks[4];
    console.log(`Nose tip: x=${noseTip.x}, y=${noseTip.y}, z=${noseTip.z}`);
  }
}

function drawLandmarks(ctx, landmarks, width, height) {
  ctx.clearRect(0, 0, width, height);

  landmarks.forEach((point, index) => {
    const x = point.x * width;
    const y = point.y * height;

    ctx.beginPath();
    ctx.arc(x, y, 1.5, 0, 2 * Math.PI);
    ctx.fillStyle = '#00ff00';
    ctx.fill();
  });
}

// Draw specific region with different color
function drawRegion(ctx, landmarks, indices, color, width, height) {
  indices.forEach((index) => {
    const point = landmarks[index];
    const x = point.x * width;
    const y = point.y * height;

    ctx.beginPath();
    ctx.arc(x, y, 3, 0, 2 * Math.PI);
    ctx.fillStyle = color;
    ctx.fill();
  });
}

function getHeadDirection(landmarks) {
  const noseTip = landmarks[4];
  const leftCheek = landmarks[234];
  const rightCheek = landmarks[454];

  const leftDist = Math.abs(noseTip.x - leftCheek.x);
  const rightDist = Math.abs(noseTip.x - rightCheek.x);

  const ratio = leftDist / rightDist;

  if (ratio > 1.4) return 'looking right';
  if (ratio < 0.6) return 'looking left';
  return 'looking forward';
}

function getFaceTilt(landmarks) {
  const leftEye = landmarks[33];
  const rightEye = landmarks[263];

  const deltaY = rightEye.y - leftEye.y;
  const deltaX = rightEye.x - leftEye.x;

  const angleRad = Math.atan2(deltaY, deltaX);
  const angleDeg = angleRad * (180 / Math.PI);

  return angleDeg; // 0 = level, positive = tilted right
}

function landmarkDistance(landmarks, indexA, indexB) {
  const a = landmarks[indexA];
  const b = landmarks[indexB];

  return Math.sqrt(
    (a.x - b.x) ** 2 +
    (a.y - b.y) ** 2 +
    (a.z - b.z) ** 2
  );
}

