  s.vy += 0.18; // gravity
  s.x += s.vx;
  s.y += s.vy;
  s.vx *= 0.99; // light air resistance
  s.rotation += s.rotSpeed;
  drawStar(s.x, s.y, s.size, s.rotation, 1 - s.age / s.maxAge, s.color);
}

import {
